require(['jquery'], function($) {
  $(document).ready(function() {
    let getCookie = function(key) {
      let keyEquals = key + "=";
      let value = false;

      document.cookie.split(';').forEach(function(c) {
        let cookie = c.trim();
        if (cookie.indexOf(keyEquals) === 0) {
          value = decodeURIComponent(cookie.substring(keyEquals.length));
        }
      });

      return value;
    }

    let setCookie = function(key, value, days) {
      var setValue = key + '=' + encodeURIComponent(new String(value));
      var setExpiration = "";

      if (days) {
        let date = new Date();
        date.setTime(date.getTime() + (days*24*60*60*1000));
        setExpiration = "; expires=" + date.toGMTString();
      }

      var cookieString = setValue + setExpiration + ";path=/";
      document.cookie  = cookieString;
    }

    let clearCookie = function(key) {
      setCookie(key,'',-1);
    }

    let animation = function(event, element, animationType) {
      const $el = $('#' + element);

      switch(animationType) {
        case 'none':
          event === 'show' ? $el.show() : $el.hide();
          break;

        case 'slide':
          event === 'show' ? $el.slideDown(1000) : $el.slideUp(1000);
          break;

        case 'fade':
          event === 'show' ? $el.fadeIn(1000) : $el.fadeOut(1000);
          break;
      }
    };

    let generateCookieConsentInitial = function (settings) {
      let content = $('<div/>', {
        id: 'cookieConsentContent',
        class: 'col-md-8'
      });

      content.append(settings.disclaimer1);

      let hideBtn = $('<button/>', {
        class: 'button',
        role: 'button',
        name: 'cookieConsentHide',
        id: 'cookieConsentHide'
      }).text(settings.buttonText);

      let rejectBtn = $('<button/>', {
        class: 'button',
        role: 'button',
        name: 'cookieConsentRejectAll',
        id: 'cookieConsentRejectAll'
      }).text(settings.rejectButtonText);

      let configBtn = $('<button/>', {
        class: 'button',
        role: 'button',
        name: 'cookieConsentConfig',
        id: 'cookieConsentConfig'
      }).text(settings.configButtonText);

      content.append(hideBtn, rejectBtn, configBtn);

      let colLeft = $('<div/>', { class: 'col-md-2' });
      let colRight = $('<div/>', { class: 'col-md-2' });

      let row = $('<div/>');

      row.append(colLeft, content, colRight);

      return row;
    }

    let generateCookieConsentPane = function (settings) {
      let activeCookieTypes = settings.activeCookieTypes.split(',');

      let cookiePane = $('<div/>', { id: 'CookieSelectPane' });

      for (let i = 0; i < activeCookieTypes.length; i++) {
        let element = activeCookieTypes[i];
        let label = settings[element + 'Label'];
        let infoBox = settings[element + 'InfoBox'];

        let input = $('<input/>', {
          id: 'CookieButton_' + element,
          class: 'CookieButton',
          tabindex: 1,
          type: 'checkbox'
        });

        if (element === 'necessary') {
          input.prop('disabled', true).prop('checked', true);
          label = settings.mandatoryLabel;
        }

        let wrapper = $('<div/>', {
          class: 'CookieSelectButtonWrapper',
          title: infoBox
        });

        let lbl = $('<label/>', {
          for: 'CookieButton_' + element
        });

        lbl.append(input).append(label);
        wrapper.append(lbl);
        cookiePane.append(wrapper);
      }

      return cookiePane;
    }

    let showDisclaimer = async function() {
      if (getCookie('cookieConsent')) {
        return;
      }

      let configElement = $('#cookie-consent-config');
      if (!configElement.length || !configElement.is('script[type="application/json"]')) {
        return;
      }

      let settings = JSON.parse(configElement.prop('textContent'));
      if (settings.active == '0' || !settings.activeCookieTypes) {
        return;
      }

      $('#cookieConsent').remove();

      var activeCookieTypes = settings.activeCookieTypes.split(',');

      let cookieConsent = $('<div/>', {
        id: 'cookieConsent',
        css: { display: 'none' }
      });

      let row = generateCookieConsentInitial(settings);
      cookieConsent.append(row);

      $('#xwikimaincontainerinner').before(cookieConsent);

      $("#cookieConsentHide").on('click', function() {
        hideDisclaimer(activeCookieTypes, settings.animation);
      });

      $("#cookieConsentRejectAll").on("click", function() {
        setCookie('cookieConsent', 'hide', 365);
        clearCookie('gdprSettings');
        animation('hide', 'cookieConsent', settings.animation);
      });

      $("#cookieConsentConfig").on("click", function() {
        let configContent = $('<div/>');
        configContent.append(settings.disclaimer2);

        let cookiePane = generateCookieConsentPane(settings);

        configContent.append(cookiePane);

        let okBtn = $('<button/>', {
          class: 'button',
          role: 'button',
          name: 'cookieConsentOK',
          id: 'cookieConsentOK'
        }).text(settings.okButtonText);

        configContent.append(okBtn);

        $("#cookieConsentContent").empty().append(configContent);

        $("#cookieConsentOK").off('click').on('click', function() {
          let selectedElements = ["necessary"];
          for (let i = 0; i < activeCookieTypes.length; i++) {
            let element = activeCookieTypes[i];

            if (element === 'necessary') {
              continue;
            }

            if ($('#CookieButton_' + element).is(':checked')) {
              selectedElements.push(element);
            }
          }
          hideDisclaimer(selectedElements, settings.animation);
        })
      });

      animation('show', 'cookieConsent', settings.animation);
    }

    let hideDisclaimer = function(param, animationType) {
      setCookie('cookieConsent', 'hide', 365);
      setCookie('gdprSettings', param, 365);
      animation('hide', 'cookieConsent', animationType);
    }

    $('#ResetCookies').on('click', function() {
      clearCookie('cookieConsent');
      clearCookie('gdprSettings');
      showDisclaimer();
    });
    showDisclaimer();
  });
});
